const results = [];

for (const item of items) {

  const supplier = item.json.property_supplier_name;
  const id = item.json.id;
  const poLast = item.json.property_po_count_last_6_months || 0;
  const poPrev = item.json.property_po_count_previous_6_months || 0;
  const rfqRate = item.json.property_rfq_response_rate || 0;
  const contractExpiry = item.json.property_contract_expiry_days || 999;

  const lateDelivery = item.json.property_late_delivery || 0;
  const deliveryDelay = item.json.property_avg_delivery_delay_days || 0;
  const qualityIssues = item.json.property_quality_issues_last_6m || 0;

  const paymentDelay = item.json.property_avg_payment_delay_days || 0;
  const disputes = item.json.property_invoice_disputes_last_6m || 0;

  // --- Trend Calculations ---
  let poDropPercent = 0;
  if (poPrev > 0) {
    poDropPercent = ((poLast - poPrev) / poPrev) * 100;
  }

  // Engagement score (0–10 scale approx)
  const engagementScore = ((rfqRate * 100) + (poLast * 2)) / 10;

  // --- Risk Flags ---
  const deliveryRisk = lateDelivery > 15 || deliveryDelay > 5 || qualityIssues > 3;
  const financialStress = paymentDelay > 30 || disputes > 2;
  const contractRenewalRisk = contractExpiry < 60;

  results.push({
    json: {
      supplier,
      id,
      po_last_6m: poLast,
      po_prev_6m: poPrev,
      po_drop_percent: Number(poDropPercent.toFixed(2)),
      rfq_response_rate: rfqRate,
      engagement_score: Number(engagementScore.toFixed(2)),
      delivery_risk_flag: deliveryRisk,
      financial_stress_flag: financialStress,
      contract_renewal_risk: contractRenewalRisk
    }
  });

}

return results;

